exploreUrl:
@js:
var result = [];
var push = (title, url, size) => result.push({
    "title": title,
    "url": url,
    "style": {
        "layout_flexGrow": 1,
        "layout_flexBasisPercent": size
    }
});
var tag = java.ajax("");
if (tag) {
    var a = org.jsoup.Jsoup.parse(tag).select(".nav li a");
    result.push({
        "title": "🔥分类小说🔥",
        "url": null,
        "style": {
            "layout_flexGrow": 1,
            "layout_flexBasisPercent": 1
        }
    });

    push("全本小说",`/quanben/category/{{page}}/`,0.33);

    var subResult = [];
    for (var i in a) {
        var title = a[i].text();
        var url = a[i].attr("href");
        var size = 0.33;
        title = String(title).replace(/\s/g, "");
        url = baseUrl+String(url).replace(/\d+\/$/, "{{page}}/");
       {
            subResult.push({
                "title": title,
                "url": url,
                "style": {
                    "layout_flexGrow": 1,
                    "layout_flexBasisPercent": size
                }
            }); 
         }
       } 

    if (subResult.length > 0) {
        if (subResult[0].title === "首页") {
            subResult.shift();
        }
    }
    if (subResult.length > 5) {
        subResult.length = subResult.length -4;
    } else {
        subResult = [];
    }
    result = result.concat(subResult);
} 
JSON.stringify(result);

ruleBookInfo.init:
@js:
(function(){
    let doc = org.jsoup.Jsoup.parse(result)
    let og = (selector) => doc.select('[property="og:' + selector + '"]').attr('content')
    return {
        name: og('novel:book_name'),
        author: og('novel:author'),
        kind: og('novel:category')
        +'•'+og('novel:status')
      +'•'+String(og('novel:update_time')),
        lastest: og('novel:lastest_chapter_name'),
        cover: og('image'),
        intro: og('description'),
        url:og('novel:read_url')
    }
})()
